module RefModule (  
    input [4:0] A,  
    input [4:0] B,  
    output [4:0] SUM,  
    output COUT  
);  
    wire [4:0] obf_G; // Generate  
    wire [4:0] P; // Propagate  
    wire [4:0] C; // Carry  

    // Generate and Propagate  
    assign obf_G = A & B;  
    assign P = A ^ B;  

    // Carry calculation  
    assign C[0] = 1'b0;  
    assign C[1] = obf_G[0] | (P[0] & C[0]);  
    assign C[2] = obf_G[1] | (P[1] & C[1]);  
    assign C[3] = obf_G[2] | (P[2] & C[2]);  
    assign C[4] = obf_G[3] | (P[3] & C[3]);  

    // Sum calculation  
    assign SUM = P ^ C[4:0];  
    assign COUT = obf_G[4] | (P[4] & C[4]);  
endmodule
